SELECT COUNT(*) AS code_count
FROM diagnostic_codes
WHERE category = 'thyroid disorders';

SELECT coding_system_name
FROM coding_systems
WHERE status = 'active';

SELECT COUNT(*) AS active_coding_systems_count
FROM coding_systems
WHERE status = 'active';

SELECT COUNT(*) AS average_accesses
FROM access_logs
WHERE code_id = 1;

SELECT code, description
FROM diagnostic_codes
WHERE code_id = 0;

SELECT COUNT(*) AS total_diagnosis_codes
FROM diagnostic_codes
WHERE entity_type = 'diagnosis';
